import flwr as flimport torchfrom torch.utils.data import DataLoaderfrom dataset import load_mnist, get_client_datafrom client import FlowerClientfrom flwr.common import Context#from graphs import generate_all_plots from attacks import Traitorimport json   #for gradients to be stored import sys from graphs2 import plot_single_experiment, plot_comparison#Attack simulation#MALICIOUS_CLIENTS = {8, 9}MALICIOUS_CLIENTS = {6, 7, 8, 9}NUM_CLIENTS       = 10NUM_ROUNDS        = 100#Aggregation functiondef weighted_average(metrics):       accuracies = [num_examples * m["accuracy"] for num_examples, m in metrics]        total = [num_examples for num_examples, _ in metrics]        return {"accuracy": sum(accuracies) / sum(total)}#use_attack & use_trust are switches for experiment layersdef run_FL(use_attack=False, use_trust=False, num_rounds=NUM_ROUNDS):        #loading all the data into server so it could simulate 10 clients itself    trainset, testset = load_mnist()    testloader = DataLoader(testset, batch_size=32)        #Creates client here    #sends client_id to dataset file get_client_data()        def client_fn(context: Context):         client_id   = int(context.node_config["partition-id"])        trainloader = get_client_data(trainset, client_id, NUM_CLIENTS)                #Flower stores this return call and calls fit() and evaluate() on it during each round.                       if use_attack and client_id in MALICIOUS_CLIENTS:                       print(f"  [SETUP] Client {client_id} is MALICIOUS")           return Traitor(client_id, trainloader, testloader).to_client()               else:           return FlowerClient(client_id, trainloader, testloader).to_client()                     #FedAvg strategy         if use_trust:                from ADL_protocol import TrustFedAvg   #Lazy importing                strategy = TrustFedAvg(             #execution of our trust protocol/placeholder for now                                                       num_clients=NUM_CLIENTS,            num_rounds=num_rounds,            alpha=0.3,                  #Controls how quickly trust scores update after each round.              beta=0.5,                   #Controls the balance between historical and current trust.                                         #Higher beta means recent behaviour matters more than past history            trust_threshold=0.1,        #The minimum trust score a client needs to have its update included in aggregation                            #The usual aggregation        fraction_fit=1.0,            fraction_evaluate=1.0,            min_fit_clients=NUM_CLIENTS,            min_evaluate_clients=NUM_CLIENTS,            min_available_clients=NUM_CLIENTS,            evaluate_metrics_aggregation_fn=weighted_average,        )                    else:        strategy = fl.server.strategy.FedAvg(            fraction_fit=1.0,                        #use 100% of clients each round            fraction_evaluate=1.0,                     #evaluate on all clients            min_fit_clients=NUM_CLIENTS,            #check if everyone available            min_evaluate_clients=NUM_CLIENTS,            min_available_clients=NUM_CLIENTS,            evaluate_metrics_aggregation_fn=weighted_average,        )# Telling FLower to Run simulation with required details#----------------------------------------------------------------------    history = fl.simulation.start_simulation(                client_fn=client_fn,        num_clients=NUM_CLIENTS,        config=fl.server.ServerConfig(num_rounds=num_rounds),         strategy=strategy,        client_resources={"num_cpus": 1},        actor_kwargs={"on_actor_init_fn": None},         ray_init_args={"ignore_reinit_error": True},    )#Save Results#----------------------------------------------------------------------    if not use_attack:        label = "honest_baseline"    elif not use_trust:        label = "fedavg_under_attack"    else:        label = "trust_protocol"    #structured dictionary logging everything about the experiment    results = {        "experiment": label,        "malicious_clients": list(MALICIOUS_CLIENTS) if use_attack else [],        "accuracy_per_round": [            float(acc) for _, acc in history.metrics_distributed["accuracy"]  #float is used here for JSON compatibility incase it returns tensors        ]    }# Save trust data if trust protocol was used    if use_trust:        trust_summary = strategy.get_trust_summary()        results["trust_history"]      = trust_summary["trust_history"]        results["trust_scores_final"] = trust_summary["trust_scores_final"]        results["exclusion_log"]      = trust_summary["exclusion_log"]#Saving results to a JSON file     with open(f"results_{label}.json", "w") as f:        json.dump(results, f, indent=2) #for readability    print(f"\n--- {label} ---")    for i, acc in enumerate(results["accuracy_per_round"]):        print(f"  Round {i+1:2d}: {acc:.4f}")    plot_single_experiment(results)        #plot_comparison()   #enable this in the final stage        return history, results#Entry Point#I created the switching logic here for our 3 stages of experiment#consider updating thisif __name__ == "__main__":    #Default to baseline if no argument given    mode = sys.argv[1] if len(sys.argv) > 1 else "baseline"    if mode == "baseline":        history, results = run_FL(use_attack=False, use_trust=False, num_rounds=5)    elif mode == "attack":        history, results = run_FL(use_attack=True, use_trust=False, num_rounds=NUM_ROUNDS)    elif mode == "trust":        history, results = run_FL(use_attack=True, use_trust=True, num_rounds=NUM_ROUNDS)    else:        print("Error, Please Re-check")        sys.exit(1)    print("\nRound-by-round accuracy:")    for round_num, metrics in enumerate(history.metrics_distributed['accuracy']):        print(f"  Round {round_num + 1}: {metrics[1]:.4f}")#----------------------------------------------------------------------#only runs if server.py is directly executed#if __name__ == "__main__":    #    history = run_FL(num_clients=10, num_rounds=5)       # Start with 5 rounds to verify everything works    # Scale to 30 once confirmed      #  print("\nRound-by-round accuracy:")   # for round_num, metrics in enumerate(history.metrics_distributed['accuracy']):    #    print(f"  Round {round_num + 1}: {metrics[1]:.4f}")        #Visualization#----------------------------------------------------------------------   # generate_all_plots(history, single_client_acc=results['accuracy_per_round'])